class TempSensor(ABC):              # Target
    @abstractmethod
    def read_celsius(self) -> float: ...

class FahrenheitProbe:              # Adaptee (incompatible API)
    def __init__(self, f): self._f = f
    def get_fahrenheit(self) -> float: return self._f

