        -state
        +save() Memento
        +restore(m)
    }
    class Memento {
        -state
    }
    class Caretaker {
        -history
        +save(orig)
        +undo(orig)
    }
    Originator ..> Memento : creates
    Caretaker --> Memento : stores opaque
    Caretaker --> Originator : save / restore

